import { useState } from "react";

import { Card } from "@/components/ui/Card";
import { Button } from "@/components/ui/Button";
import { ContentGrid } from "@/components/layout/ContentGrid";
import { StatTile } from "@/components/ui/StatTile";

import { useGameStore } from "@/state/store";
import {
  selectCreditProfile,
  selectNetWorth,
  selectPlayerBusinessLoanDebt,
  selectPlayerMortgageDebt,
  selectPlayerProperties,
  selectPlayerRealEstateEquity,
} from "@/state/selectors";
import { formatMoney } from "@/lib/money";
import type { Property } from "@/types/game";

const BAND_COLORS: Record<string, string> = {
  emerald: "text-emerald-300",
  lime: "text-lime-300",
  amber: "text-amber-300",
  orange: "text-orange-300",
  red: "text-red-300",
};

export function FinancePage() {
  const game = useGameStore((s) => s.game)!;
  const refinance = useGameStore((s) => s.refinance);
  const sellProperty = useGameStore((s) => s.sellProperty);
  const sellHostedProperty = useGameStore((s) => s.sellHostedProperty);
  const [banner, setBanner] = useState<string | undefined>();
  const [confirmSell, setConfirmSell] = useState<Property | undefined>();

  const credit = selectCreditProfile(game);
  const netWorth = selectNetWorth(game);
  const equity = selectPlayerRealEstateEquity(game);
  const mortgageDebt = selectPlayerMortgageDebt(game);
  const businessLoanDebt = selectPlayerBusinessLoanDebt(game);
  const ownedProps = selectPlayerProperties(game);
  const businessLoans = Object.values(game.businessLoans ?? {}).filter((l) => {
    if (l.balance <= 0) return false;
    const biz = l.businessId ? game.businesses[l.businessId] : undefined;
    // Include if biz is player-owned OR the biz has been closed (liability survives).
    return !biz || biz.ownerId === game.player.id;
  });

  return (
    <div className="space-y-4">
      <header>
        <h1 className="text-2xl font-bold">Finance</h1>
        <p className="text-ink-400 text-sm mt-1">
          Your credit, real estate, and debt. Every missed mortgage payment
          costs 35 points. On-time streaks quietly build you back up.
        </p>
      </header>

      {banner && (
        <div className="rounded-xl border border-ink-700 bg-ink-900/60 text-sm text-ink-50 px-3 py-2">
          {banner}
        </div>
      )}

      <Card
        title="Credit profile"
        subtitle={`${credit.score} · ${credit.band.label}`}
        trailing={
          <span className={`text-xs ${BAND_COLORS[credit.band.color] ?? "text-ink-300"}`}>
            {(credit.quotedMortgageRate * 100).toFixed(2)}% quoted
          </span>
        }
      >
        <div className="grid grid-cols-3 gap-2 text-xs">
          <StatTile
            label="Max LTV"
            value={credit.band.minLtv > 0 ? `${Math.round(credit.band.minLtv * 100)}%` : "Denied"}
          />
          <StatTile
            label="Rate spread"
            value={`+${credit.band.spreadPct.toFixed(1)}%`}
          />
          <StatTile
            label="Missed YTD"
            value={String(credit.missedThisYear)}
            hint={credit.missedThisYear > 0 ? "Each −35 credit" : "Clean streak"}
          />
        </div>
      </Card>

      <ContentGrid>
        <StatTile label="Net worth" value={formatMoney(netWorth, { compact: true })} />
        <StatTile
          label="Real estate equity"
          value={formatMoney(equity, { compact: true })}
        />
        <StatTile
          label="Mortgage debt"
          value={formatMoney(mortgageDebt, { compact: true })}
        />
        <StatTile
          label="Business debt"
          value={formatMoney(businessLoanDebt, { compact: true })}
          hint={businessLoans.length > 0 ? `${businessLoans.length} loan${businessLoans.length === 1 ? "" : "s"} outstanding` : "No SBA debt"}
        />
      </ContentGrid>

      {businessLoans.length > 0 && (
        <Card title="Business loans" subtitle={`${businessLoans.length} outstanding · SBA-style, personally guaranteed`}>
          <div className="flex flex-col gap-2">
            {businessLoans.map((loan) => {
              const biz = loan.businessId ? game.businesses[loan.businessId] : undefined;
              const paid = loan.principal - loan.balance;
              const pct = loan.principal > 0 ? Math.round((paid / loan.principal) * 100) : 0;
              return (
                <div
                  key={loan.id}
                  className="rounded-xl border border-ink-800 bg-ink-900/40 p-3"
                >
                  <div className="flex items-start justify-between gap-2">
                    <div className="min-w-0">
                      <div className="text-sm text-ink-50 truncate">
                        💼 {biz?.name ?? "Closed business"}
                      </div>
                      <div className="text-xs text-ink-400">
                        {(loan.annualRate * 100).toFixed(2)}% · {loan.termMonths}mo term ·{" "}
                        {(loan.missedPaymentsThisYear ?? 0) > 0
                          ? `${loan.missedPaymentsThisYear} missed YTD`
                          : "current"}
                      </div>
                    </div>
                    <div className="text-right text-xs">
                      <div className="text-ink-50">
                        {formatMoney(loan.balance, { compact: true })}
                      </div>
                      <div className="text-ink-400">balance</div>
                    </div>
                  </div>

                  <div className="grid grid-cols-3 gap-2 mt-3 text-[11px]">
                    <div>
                      <div className="text-ink-400">Original</div>
                      <div className="text-ink-50">
                        {formatMoney(loan.principal, { compact: true })}
                      </div>
                    </div>
                    <div>
                      <div className="text-ink-400">Paid down</div>
                      <div className="text-money">{pct}%</div>
                    </div>
                    <div>
                      <div className="text-ink-400">Payment</div>
                      <div className="text-ink-50">
                        {formatMoney(loan.monthlyPayment, { compact: true })}/mo
                      </div>
                    </div>
                  </div>
                </div>
              );
            })}
          </div>
        </Card>
      )}

      <Card title="Your properties" subtitle={`${ownedProps.length} owned`}>
        {ownedProps.length === 0 ? (
          <p className="text-xs text-ink-400">
            You don&apos;t own any properties yet. Visit Markets to browse listings.
          </p>
        ) : (
          <div className="flex flex-col gap-3">
            {ownedProps.map((p) => {
              const loan = p.mortgageId ? game.mortgages[p.mortgageId] : undefined;
              const equityP = p.valueCents - (loan?.balance ?? 0);
              const market = game.markets[p.marketId];
              return (
                <div
                  key={p.id}
                  className="rounded-xl border border-ink-800 bg-ink-900/40 p-3"
                >
                  <div className="flex items-start justify-between gap-2">
                    <div className="min-w-0">
                      <div className="text-sm text-ink-50 truncate">
                        🏢 {p.address}
                      </div>
                      <div className="text-xs text-ink-400">
                        {market?.name ?? p.marketId} · {p.class}-class · {p.sqft.toLocaleString()} sqft
                      </div>
                    </div>
                    <div className="text-right text-xs">
                      <div className="text-ink-50">
                        {formatMoney(p.valueCents, { compact: true })}
                      </div>
                      <div className="text-ink-400">appraised</div>
                    </div>
                  </div>

                  <div className="grid grid-cols-3 gap-2 mt-3 text-[11px]">
                    <div>
                      <div className="text-ink-400">Equity</div>
                      <div className="text-money">
                        {formatMoney(equityP, { compact: true })}
                      </div>
                    </div>
                    <div>
                      <div className="text-ink-400">Mortgage</div>
                      <div className="text-ink-50">
                        {loan
                          ? `${formatMoney(loan.balance, { compact: true })} @ ${(loan.annualRate * 100).toFixed(2)}%`
                          : "Paid off"}
                      </div>
                    </div>
                    <div>
                      <div className="text-ink-400">Payment</div>
                      <div className="text-ink-50">
                        {loan ? `${formatMoney(loan.monthlyPayment, { compact: true })}/mo` : "—"}
                      </div>
                    </div>
                  </div>

                  <div className="flex gap-2 mt-3">
                    {loan && (
                      <Button
                        size="xs"
                        variant="secondary"
                        onClick={() => {
                          setBanner(undefined);
                          const res = refinance(loan.id);
                          if (!res.ok) setBanner(res.error);
                          else
                            setBanner(
                              `Refinanced ${p.address} — new payment ${formatMoney(res.newPaymentCents ?? 0, { compact: true })}/mo.`,
                            );
                        }}
                      >
                        Refinance
                      </Button>
                    )}
                    <Button
                      size="xs"
                      variant="ghost"
                      onClick={() => {
                        setBanner(undefined);
                        if (p.hostedBusinessId) {
                          // Hosted property — show the relocate-or-close
                          // confirmation before touching anything.
                          setConfirmSell(p);
                          return;
                        }
                        const res = sellProperty(p.id);
                        if (!res.ok) setBanner(res.error);
                        else
                          setBanner(
                            `Sold ${p.address} — ${formatMoney(res.proceedsCents ?? 0, { compact: true })} proceeds.`,
                          );
                      }}
                      title={
                        p.hostedBusinessId
                          ? "Hosted property — selling will relocate or close the business."
                          : "Sell at appraised value."
                      }
                    >
                      {p.hostedBusinessId ? "Sell (hosted)…" : "Sell at appraisal"}
                    </Button>
                  </div>
                </div>
              );
            })}
          </div>
        )}
      </Card>

      <p className="text-xs text-ink-500">
        Mortgage, maintenance, and appreciation all settle once per in-game
        month. Rivals (operators) will compete for listings; disruptors rent.
      </p>

      {confirmSell && (
        <SellHostedConfirmDialog
          property={confirmSell}
          hostedName={
            confirmSell.hostedBusinessId
              ? game.businesses[confirmSell.hostedBusinessId]?.name
              : undefined
          }
          onCancel={() => setConfirmSell(undefined)}
          onConfirm={() => {
            const target = confirmSell;
            setConfirmSell(undefined);
            setBanner(undefined);
            const res = sellHostedProperty(target.id);
            if (!res.ok) {
              setBanner(res.error ?? "Couldn't sell that property.");
              return;
            }
            const proceeds = formatMoney(res.proceedsCents ?? 0, { compact: true });
            const bizName =
              target.hostedBusinessId
                ? game.businesses[target.hostedBusinessId]?.name ?? "the business"
                : "the business";
            if (res.outcome === "relocated") {
              const deposit = formatMoney(res.depositCents ?? 0, { compact: true });
              setBanner(
                `Sold ${target.address} — ${proceeds} proceeds. Relocated ${bizName} to a lease (paid ${deposit} deposit).`,
              );
            } else if (res.outcome === "closed") {
              setBanner(
                `Sold ${target.address} — ${proceeds} proceeds. ${bizName} couldn't afford a 2-month lease deposit and was closed.`,
              );
            } else {
              setBanner(
                `Sold ${target.address} — ${proceeds} proceeds.`,
              );
            }
          }}
        />
      )}
    </div>
  );
}

function SellHostedConfirmDialog({
  property,
  hostedName,
  onCancel,
  onConfirm,
}: {
  property: Property;
  hostedName?: string;
  onCancel: () => void;
  onConfirm: () => void;
}) {
  return (
    <div
      role="dialog"
      aria-modal="true"
      aria-labelledby="sell-hosted-title"
      className="fixed inset-0 z-50 flex items-center justify-center bg-black/60 px-4"
      onClick={(e) => {
        if (e.target === e.currentTarget) onCancel();
      }}
    >
      <div className="w-full max-w-md rounded-2xl border border-ink-700 bg-ink-900 shadow-card p-5">
        <h2
          id="sell-hosted-title"
          className="text-lg font-semibold text-ink-50"
        >
          Sell {property.address}?
        </h2>
        <p className="mt-2 text-sm text-ink-300">
          This property hosts <span className="text-ink-50 font-medium">{hostedName ?? "a business"}</span>.
          You'll still receive the appraised value as proceeds, but the
          business needs somewhere to go.
        </p>

        <ul className="mt-3 space-y-2 text-xs text-ink-200">
          <li className="rounded-lg border border-money/40 bg-money/5 px-3 py-2">
            <span className="text-money font-semibold">If affordable:</span>{" "}
            {hostedName ?? "The business"} relocates to a commercial lease.
            A 2-month deposit is pulled from its operating cash first, then
            from your personal cash.
          </li>
          <li className="rounded-lg border border-loss/40 bg-loss/5 px-3 py-2">
            <span className="text-loss font-semibold">If not:</span>{" "}
            {hostedName ?? "The business"} is closed immediately (voluntary
            close — no bankruptcy hit). The property still sells.
          </li>
        </ul>

        <div className="mt-5 flex justify-end gap-2">
          <Button size="sm" variant="ghost" onClick={onCancel}>
            Cancel
          </Button>
          <Button size="sm" variant="primary" onClick={onConfirm}>
            Sell property
          </Button>
        </div>
      </div>
    </div>
  );
}
